package com.cardiofit.flink.models;

import com.fasterxml.jackson.annotation.JsonIgnoreProperties;
import com.fasterxml.jackson.annotation.JsonProperty;
import java.io.Serializable;
import java.time.Instant;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

/**
 * Pattern event model representing detected clinical patterns, trends, and anomalies
 * Generated by Module 4: Pattern Detection (CEP & Windowed Analytics)
 */
@JsonIgnoreProperties(ignoreUnknown = true)
public class PatternEvent implements Serializable {
    private static final long serialVersionUID = 1L;

    @JsonProperty("id")
    private String id;

    @JsonProperty("pattern_type")
    private String patternType;

    @JsonProperty("patient_id")
    private String patientId;

    @JsonProperty("encounter_id")
    private String encounterId;

    @JsonProperty("detection_time")
    private long detectionTime;

    @JsonProperty("pattern_start_time")
    private Long patternStartTime;

    @JsonProperty("pattern_end_time")
    private Long patternEndTime;

    @JsonProperty("severity")
    private String severity;

    @JsonProperty("confidence")
    private double confidence;

    @JsonProperty("pattern_details")
    private Map<String, Object> patternDetails;

    @JsonProperty("involved_events")
    private List<String> involvedEvents;

    @JsonProperty("recommended_actions")
    private List<String> recommendedActions;

    @JsonProperty("clinical_context")
    private ClinicalContext clinicalContext;

    @JsonProperty("pattern_metadata")
    private PatternMetadata patternMetadata;

    @JsonProperty("tags")
    private Set<String> tags;

    @JsonProperty("correlation_id")
    private String correlationId;

    @JsonProperty("acknowledged")
    private boolean acknowledged;

    @JsonProperty("acknowledgment_time")
    private Long acknowledgmentTime;

    @JsonProperty("acknowledged_by")
    private String acknowledgedBy;

    @JsonProperty("priority")
    private Integer priority;  // 1 (highest/CRITICAL) to 4 (lowest/LOW)

    // Default constructor
    public PatternEvent() {
        this.detectionTime = System.currentTimeMillis();
        this.acknowledged = false;
        this.tags = new HashSet<>();
        this.involvedEvents = new ArrayList<>();
        this.recommendedActions = new ArrayList<>();
    }

    // Builder pattern
    public static Builder builder() {
        return new Builder();
    }

    public static class Builder {
        private PatternEvent event = new PatternEvent();

        public Builder id(String id) {
            event.id = id;
            return this;
        }

        public Builder patternType(String patternType) {
            event.patternType = patternType;
            return this;
        }

        public Builder patientId(String patientId) {
            event.patientId = patientId;
            return this;
        }

        public Builder encounterId(String encounterId) {
            event.encounterId = encounterId;
            return this;
        }

        public Builder detectionTime(long detectionTime) {
            event.detectionTime = detectionTime;
            return this;
        }

        public Builder patternStartTime(long patternStartTime) {
            event.patternStartTime = patternStartTime;
            return this;
        }

        public Builder patternEndTime(long patternEndTime) {
            event.patternEndTime = patternEndTime;
            return this;
        }

        public Builder severity(String severity) {
            event.severity = severity;
            return this;
        }

        public Builder confidence(double confidence) {
            event.confidence = confidence;
            return this;
        }

        public Builder patternDetails(Map<String, Object> patternDetails) {
            event.patternDetails = patternDetails;
            return this;
        }

        public Builder involvedEvents(List<String> involvedEvents) {
            event.involvedEvents = involvedEvents;
            return this;
        }

        public Builder recommendedActions(List<String> recommendedActions) {
            event.recommendedActions = recommendedActions;
            return this;
        }

        public Builder clinicalContext(ClinicalContext clinicalContext) {
            event.clinicalContext = clinicalContext;
            return this;
        }

        public Builder correlationId(String correlationId) {
            event.correlationId = correlationId;
            return this;
        }

        public PatternEvent build() {
            return event;
        }
    }

    // Getters and Setters
    public String getId() { return id; }
    public void setId(String id) { this.id = id; }

    public String getPatternType() { return patternType; }
    public void setPatternType(String patternType) { this.patternType = patternType; }

    public String getPatientId() { return patientId; }
    public void setPatientId(String patientId) { this.patientId = patientId; }

    public String getEncounterId() { return encounterId; }
    public void setEncounterId(String encounterId) { this.encounterId = encounterId; }

    public long getDetectionTime() { return detectionTime; }
    public void setDetectionTime(long detectionTime) { this.detectionTime = detectionTime; }

    public Long getPatternStartTime() { return patternStartTime; }
    public void setPatternStartTime(Long patternStartTime) { this.patternStartTime = patternStartTime; }

    public Long getPatternEndTime() { return patternEndTime; }
    public void setPatternEndTime(Long patternEndTime) { this.patternEndTime = patternEndTime; }

    public String getSeverity() { return severity; }
    public void setSeverity(String severity) { this.severity = severity; }

    public double getConfidence() { return confidence; }
    public void setConfidence(double confidence) { this.confidence = confidence; }

    public Map<String, Object> getPatternDetails() { return patternDetails; }
    public void setPatternDetails(Map<String, Object> patternDetails) { this.patternDetails = patternDetails; }

    public List<String> getInvolvedEvents() { return involvedEvents; }
    public void setInvolvedEvents(List<String> involvedEvents) { this.involvedEvents = involvedEvents; }

    public List<String> getRecommendedActions() { return recommendedActions; }
    public void setRecommendedActions(List<String> recommendedActions) { this.recommendedActions = recommendedActions; }

    public ClinicalContext getClinicalContext() { return clinicalContext; }
    public void setClinicalContext(ClinicalContext clinicalContext) { this.clinicalContext = clinicalContext; }

    public PatternMetadata getPatternMetadata() { return patternMetadata; }
    public void setPatternMetadata(PatternMetadata patternMetadata) { this.patternMetadata = patternMetadata; }

    public Set<String> getTags() { return tags; }
    public void setTags(Set<String> tags) { this.tags = tags; }

    public String getCorrelationId() { return correlationId; }
    public void setCorrelationId(String correlationId) { this.correlationId = correlationId; }

    public boolean isAcknowledged() { return acknowledged; }
    public void setAcknowledged(boolean acknowledged) { this.acknowledged = acknowledged; }

    public Long getAcknowledgmentTime() { return acknowledgmentTime; }
    public void setAcknowledgmentTime(Long acknowledgmentTime) { this.acknowledgmentTime = acknowledgmentTime; }

    public String getAcknowledgedBy() { return acknowledgedBy; }
    public void setAcknowledgedBy(String acknowledgedBy) { this.acknowledgedBy = acknowledgedBy; }

    /**
     * Get priority level for Module 5 alert routing
     * Priority is auto-calculated from severity if not explicitly set
     * @return 1 (highest/CRITICAL) to 4 (lowest/LOW)
     */
    public Integer getPriority() {
        // If priority explicitly set, use it
        if (priority != null) {
            return priority;
        }

        // Auto-calculate from severity
        if (severity == null) {
            return 4;  // Default to lowest priority
        }

        switch (severity.toUpperCase()) {
            case "CRITICAL":
                return 1;  // Highest priority
            case "HIGH":
                return 2;
            case "MODERATE":
                return 3;
            case "LOW":
            default:
                return 4;  // Lowest priority
        }
    }

    public void setPriority(Integer priority) { this.priority = priority; }

    // Utility methods
    /**
     * Add a tag to this pattern event
     */
    public void addTag(String tag) {
        if (tags == null) {
            tags = new HashSet<>();
        }
        tags.add(tag);
    }

    /**
     * Remove a tag from this pattern event
     */
    public void removeTag(String tag) {
        if (tags != null) {
            tags.remove(tag);
        }
    }

    /**
     * Check if pattern has a specific tag
     */
    public boolean hasTag(String tag) {
        return tags != null && tags.contains(tag);
    }

    /**
     * Add an involved event ID
     */
    public void addInvolvedEvent(String eventId) {
        if (involvedEvents == null) {
            involvedEvents = new ArrayList<>();
        }
        involvedEvents.add(eventId);
    }

    /**
     * Add a recommended action
     */
    public void addRecommendedAction(String action) {
        if (recommendedActions == null) {
            recommendedActions = new ArrayList<>();
        }
        recommendedActions.add(action);
    }

    /**
     * Check if pattern is high severity
     */
    public boolean isHighSeverity() {
        return "HIGH".equalsIgnoreCase(severity) || "CRITICAL".equalsIgnoreCase(severity);
    }

    /**
     * Check if pattern has high confidence
     */
    public boolean isHighConfidence() {
        return confidence > 0.8;
    }

    /**
     * Get pattern duration in milliseconds
     */
    public Long getPatternDuration() {
        if (patternStartTime != null && patternEndTime != null) {
            return patternEndTime - patternStartTime;
        }
        return null;
    }

    /**
     * Get pattern duration in hours
     */
    public Double getPatternDurationHours() {
        Long duration = getPatternDuration();
        return duration != null ? duration / (1000.0 * 3600.0) : null;
    }

    /**
     * Check if pattern requires immediate action
     */
    public boolean requiresImmediateAction() {
        return isHighSeverity() && isHighConfidence() && !acknowledged;
    }

    /**
     * Get number of involved events
     */
    public int getInvolvedEventCount() {
        return involvedEvents != null ? involvedEvents.size() : 0;
    }

    /**
     * Acknowledge this pattern event
     */
    public void acknowledge(String acknowledgedBy) {
        this.acknowledged = true;
        this.acknowledgmentTime = System.currentTimeMillis();
        this.acknowledgedBy = acknowledgedBy;
    }

    /**
     * Get a specific pattern detail
     */
    public Object getPatternDetail(String key) {
        return patternDetails != null ? patternDetails.get(key) : null;
    }

    /**
     * Set a specific pattern detail
     */
    public void setPatternDetail(String key, Object value) {
        if (patternDetails == null) {
            patternDetails = new java.util.HashMap<>();
        }
        patternDetails.put(key, value);
    }

    /**
     * Check if pattern is a deterioration pattern
     */
    public boolean isDeteriorationPattern() {
        return "CLINICAL_DETERIORATION".equals(patternType);
    }

    /**
     * Check if pattern is a medication adherence pattern
     */
    public boolean isMedicationAdherencePattern() {
        return "MEDICATION_ADHERENCE".equals(patternType);
    }

    /**
     * Check if pattern is an anomaly
     */
    public boolean isAnomalyPattern() {
        return "ANOMALY_DETECTION".equals(patternType);
    }

    /**
     * Check if pattern is a trend analysis
     */
    public boolean isTrendPattern() {
        return "TREND_ANALYSIS".equals(patternType);
    }

    /**
     * Check if pattern is pathway compliance related
     */
    public boolean isPathwayCompliancePattern() {
        return "PATHWAY_COMPLIANCE".equals(patternType);
    }

    /**
     * Get pattern detection timestamp as Instant
     * @return Instant representing when pattern was detected
     */
    public Instant getTimestamp() {
        return Instant.ofEpochMilli(detectionTime);
    }

    @Override
    public String toString() {
        return "PatternEvent{" +
            "id='" + id + '\'' +
            ", patternType='" + patternType + '\'' +
            ", patientId='" + patientId + '\'' +
            ", detectionTime=" + Instant.ofEpochMilli(detectionTime) +
            ", severity='" + severity + '\'' +
            ", confidence=" + confidence +
            ", acknowledged=" + acknowledged +
            ", involvedEvents=" + getInvolvedEventCount() +
            '}';
    }

    // Inner classes for structured data
    public static class ClinicalContext implements Serializable {
        private String department;
        private String unit;
        private String careTeam;
        private String primaryDiagnosis;
        private List<String> activeProblems;
        private String acuityLevel;
        private List<String> recentAlerts;  // Recent alert history for this patient

        public ClinicalContext() {}

        // Getters and setters
        public String getDepartment() { return department; }
        public void setDepartment(String department) { this.department = department; }

        public String getUnit() { return unit; }
        public void setUnit(String unit) { this.unit = unit; }

        public String getCareTeam() { return careTeam; }
        public void setCareTeam(String careTeam) { this.careTeam = careTeam; }

        public String getPrimaryDiagnosis() { return primaryDiagnosis; }
        public void setPrimaryDiagnosis(String primaryDiagnosis) { this.primaryDiagnosis = primaryDiagnosis; }

        public List<String> getActiveProblems() { return activeProblems; }
        public void setActiveProblems(List<String> activeProblems) { this.activeProblems = activeProblems; }

        public String getAcuityLevel() { return acuityLevel; }
        public void setAcuityLevel(String acuityLevel) { this.acuityLevel = acuityLevel; }

        public List<String> getRecentAlerts() { return recentAlerts; }
        public void setRecentAlerts(List<String> recentAlerts) { this.recentAlerts = recentAlerts; }
    }

    public static class PatternMetadata implements Serializable {
        private String algorithm;
        private String version;
        private Map<String, Object> algorithmParameters;
        private double processingTime;
        private String qualityScore;
        private List<String> validationRules;

        public PatternMetadata() {}

        // Getters and setters
        public String getAlgorithm() { return algorithm; }
        public void setAlgorithm(String algorithm) { this.algorithm = algorithm; }

        public String getVersion() { return version; }
        public void setVersion(String version) { this.version = version; }

        public Map<String, Object> getAlgorithmParameters() { return algorithmParameters; }
        public void setAlgorithmParameters(Map<String, Object> algorithmParameters) { this.algorithmParameters = algorithmParameters; }

        public double getProcessingTime() { return processingTime; }
        public void setProcessingTime(double processingTime) { this.processingTime = processingTime; }

        public String getQualityScore() { return qualityScore; }
        public void setQualityScore(String qualityScore) { this.qualityScore = qualityScore; }

        public List<String> getValidationRules() { return validationRules; }
        public void setValidationRules(List<String> validationRules) { this.validationRules = validationRules; }
    }

    // Enum for pattern types
    public enum PatternType {
        CLINICAL_DETERIORATION("Clinical deterioration detected"),
        MEDICATION_ADHERENCE("Medication adherence pattern"),
        VITAL_SIGNS_TREND("Vital signs trend analysis"),
        PATHWAY_COMPLIANCE("Clinical pathway compliance"),
        ANOMALY_DETECTION("Anomaly or outlier detected"),
        TREND_ANALYSIS("Statistical trend analysis"),
        PROTOCOL_MONITORING("Clinical protocol monitoring"),
        EARLY_WARNING("Early warning system alert"),
        CARE_COORDINATION("Care coordination pattern"),
        QUALITY_INDICATOR("Quality indicator pattern");

        private final String description;

        PatternType(String description) {
            this.description = description;
        }

        public String getDescription() {
            return description;
        }
    }

    // Enum for severity levels
    public enum Severity {
        LOW("Low priority, routine monitoring"),
        MODERATE("Moderate priority, enhanced monitoring"),
        HIGH("High priority, immediate attention"),
        CRITICAL("Critical priority, urgent intervention");

        private final String description;

        Severity(String description) {
            this.description = description;
        }

        public String getDescription() {
            return description;
        }

        public boolean requiresImmediateAction() {
            return this == HIGH || this == CRITICAL;
        }
    }

    // Enum for recommended actions
    public enum RecommendedAction {
        // Assessment actions
        IMMEDIATE_ASSESSMENT_REQUIRED("Immediate clinical assessment required"),
        REASSESS_IN_15_MINUTES("Reassess patient in 15 minutes"),
        REASSESS_IN_30_MINUTES("Reassess patient in 30 minutes"),
        REASSESS_IN_1_HOUR("Reassess patient in 1 hour"),

        // Escalation actions
        ESCALATE_TO_PHYSICIAN("Escalate to attending physician"),
        ESCALATE_TO_SPECIALIST("Escalate to specialist"),
        ESCALATE_TO_RAPID_RESPONSE("Activate rapid response team"),
        ESCALATE_TO_ICU("Consider ICU consultation"),

        // Monitoring actions
        INCREASE_MONITORING_FREQUENCY("Increase monitoring frequency"),
        CONTINUOUS_MONITORING("Initiate continuous monitoring"),
        VITAL_SIGNS_Q15MIN("Vital signs every 15 minutes"),
        VITAL_SIGNS_Q30MIN("Vital signs every 30 minutes"),

        // Medication actions
        VERIFY_PATIENT_STATUS("Verify patient status before medication"),
        RESCHEDULE_MEDICATION("Reschedule missed medication"),
        ASSESS_ADHERENCE_BARRIERS("Assess medication adherence barriers"),
        REVIEW_MEDICATION_ORDERS("Review current medication orders"),

        // Clinical actions
        CLINICAL_ASSESSMENT("Perform focused clinical assessment"),
        CONSIDER_INTERVENTION("Consider clinical intervention"),
        UPDATE_CARE_PLAN("Update patient care plan"),
        NOTIFY_CARE_TEAM("Notify primary care team"),

        // Documentation actions
        DOCUMENT_FINDINGS("Document clinical findings"),
        UPDATE_PROBLEM_LIST("Update patient problem list"),
        CREATE_CARE_NOTE("Create care coordination note");

        private final String description;

        RecommendedAction(String description) {
            this.description = description;
        }

        public String getDescription() {
            return description;
        }
    }

    public String getUrgency() {
        if ("CRITICAL".equals(severity)) return "IMMEDIATE";
        if ("HIGH".equals(severity)) return "URGENT";
        if ("MODERATE".equals(severity)) return "MODERATE";
        return "LOW";
    }

    // Additional utility methods for backward compatibility and EnhancedAlert integration

    /**
     * Alias for getPatternType() to maintain backward compatibility
     */
    public String getPatternName() {
        return patternType;
    }

    /**
     * Get clinical significance description based on severity and pattern type
     */
    public String getClinicalSignificance() {
        if (isHighSeverity()) {
            return "High clinical significance - requires immediate attention";
        } else if ("MODERATE".equals(severity)) {
            return "Moderate clinical significance - monitor closely";
        } else {
            return "Low clinical significance - routine monitoring";
        }
    }

    /**
     * Get contributing factors from pattern details
     */
    @SuppressWarnings("unchecked")
    public List<String> getContributingFactors() {
        if (patternDetails != null && patternDetails.containsKey("contributing_factors")) {
            Object factors = patternDetails.get("contributing_factors");
            if (factors instanceof List) {
                return (List<String>) factors;
            }
        }
        return new ArrayList<>();
    }

    /**
     * Get mitigating factors from pattern details
     */
    @SuppressWarnings("unchecked")
    public List<String> getMitigatingFactors() {
        if (patternDetails != null && patternDetails.containsKey("mitigating_factors")) {
            Object factors = patternDetails.get("mitigating_factors");
            if (factors instanceof List) {
                return (List<String>) factors;
            }
        }
        return new ArrayList<>();
    }

    /**
     * Alias for getPriority() to maintain backward compatibility
     */
    public Integer getActionPriority() {
        return getPriority();
    }

    /**
     * Get time window description for the pattern
     */
    public String getTimeWindow() {
        Long duration = getPatternDuration();
        if (duration != null) {
            long hours = duration / (1000 * 3600);
            if (hours < 1) {
                long minutes = duration / (1000 * 60);
                return minutes + " minutes";
            } else if (hours < 24) {
                return hours + " hours";
            } else {
                long days = hours / 24;
                return days + " days";
            }
        }
        return "Unknown";
    }

    /**
     * Alias for getConfidence() to maintain backward compatibility
     */
    public double getConfidenceScore() {
        return confidence;
    }

    /**
     * Get trend direction from pattern details
     */
    public String getTrendDirection() {
        if (patternDetails != null && patternDetails.containsKey("trend_direction")) {
            return String.valueOf(patternDetails.get("trend_direction"));
        }
        return "UNKNOWN";
    }

    /**
     * Alias for getSeverity() to maintain backward compatibility
     */
    public String getSeverityLevel() {
        return severity;
    }

    /**
     * Get evidence strength description based on confidence and involved events
     */
    public String getEvidenceStrength() {
        int eventCount = getInvolvedEventCount();
        if (isHighConfidence() && eventCount >= 3) {
            return "STRONG - High confidence with multiple supporting events";
        } else if (confidence > 0.6 && eventCount >= 2) {
            return "MODERATE - Good confidence with supporting events";
        } else if (confidence > 0.4) {
            return "WEAK - Limited confidence or supporting evidence";
        } else {
            return "VERY_WEAK - Low confidence pattern";
        }
    }

    /**
     * Get relevant vital signs from pattern details
     */
    @SuppressWarnings("unchecked")
    public List<String> getRelevantVitals() {
        if (patternDetails != null && patternDetails.containsKey("relevant_vitals")) {
            Object vitals = patternDetails.get("relevant_vitals");
            if (vitals instanceof List) {
                return (List<String>) vitals;
            }
        }
        return new ArrayList<>();
    }

    /**
     * Get relevant lab values from pattern details
     */
    @SuppressWarnings("unchecked")
    public List<String> getRelevantLabs() {
        if (patternDetails != null && patternDetails.containsKey("relevant_labs")) {
            Object labs = patternDetails.get("relevant_labs");
            if (labs instanceof List) {
                return (List<String>) labs;
            }
        }
        return new ArrayList<>();
    }
}
